DROP TABLE IF EXISTS `deleted_bid_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `deleted_bid_log` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `order_number` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `product_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `type` int NOT NULL DEFAULT '2' COMMENT 'Bid=2, Purchase=3',
  `bid_amount` double(20,2) DEFAULT NULL,
  `amount` double(10,2) DEFAULT NULL,
  `tax_amount` double(10,2) DEFAULT NULL,
  `quantity` int DEFAULT NULL,
  `billing_first_name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `billing_last_name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `billing_address` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `billing_country_id` bigint unsigned DEFAULT NULL,
  `billing_state_id` bigint unsigned DEFAULT NULL,
  `billing_city_id` bigint unsigned DEFAULT NULL,
  `billing_post_code` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `billing_phone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `billing_email` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_first_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_last_name` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_address` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_country_id` int DEFAULT NULL,
  `shipping_state_id` int DEFAULT NULL,
  `shipping_city_id` int DEFAULT NULL,
  `shipping_post_code` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_phone` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `shipping_email` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `message` longtext COLLATE utf8mb4_unicode_ci,
  `merchant_id` int DEFAULT NULL,
  `status` int NOT NULL DEFAULT '1' COMMENT 'Processing=1, Win=2, Reject=3, Completed=4, On Hold=5, Delivered=6, Refunded=7, Shipped=8',
  `payment_status` int NOT NULL DEFAULT '1' COMMENT 'Partials=1, Unpaid=2, Paid=3',
  `view` int NOT NULL DEFAULT '0',
  `win_status` int NOT NULL DEFAULT '0',
  `is_bank` int DEFAULT NULL,
  `is_restricted` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
