--
-- Table structure for table `products`
--

DROP TABLE IF EXISTS `products`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `products` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` mediumtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_title` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meta_keyward` longtext COLLATE utf8mb4_unicode_ci,
  `meta_description` text COLLATE utf8mb4_unicode_ci,
  `author_id` bigint unsigned NOT NULL,
  `short_desc` text COLLATE utf8mb4_unicode_ci,
  `long_desc` longtext COLLATE utf8mb4_unicode_ci,
  `category_id` bigint unsigned NOT NULL,
  `features_image` text COLLATE utf8mb4_unicode_ci,
  `sale_type` int NOT NULL DEFAULT '1' COMMENT 'Action=1, Direct=2',
  `schedule_type` int NOT NULL DEFAULT '1' COMMENT 'Yes=1, No=2',
  `min_deposit` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `min_deposit_type` int NOT NULL DEFAULT '1' COMMENT 'Percent=1, Fixed=2',
  `quantity` int NOT NULL DEFAULT '1',
  `price` double(10,2) DEFAULT NULL,
  `sale_price` double(10,2) DEFAULT NULL,
  `min_bid_price` double(10,2) DEFAULT NULL,
  `start_date` timestamp NULL DEFAULT NULL,
  `end_date` timestamp NULL DEFAULT NULL,
  `status` int NOT NULL DEFAULT '1' COMMENT 'Published=1, Draft=2, Pending=3, Inactive=4',
  `enable_seo` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `add_balance_one` int NOT NULL,
  `add_balance_two` int NOT NULL,
  `add_balance_three` int NOT NULL,
  `add_balance_four` int NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `group_id` bigint unsigned NOT NULL DEFAULT '1',
  `location` varchar(191) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `products_author_id_foreign` (`author_id`),
  KEY `products_category_id_foreign` (`category_id`),
