INSERT INTO `widget_content_translations` (`id`, `widget_content_id`, `page_id`, `widget_content`, `lang`, `created_at`, `updated_at`) VALUES (1,1,1,'{\"live_auctions_title\":\"\\u0627\\u0644\\u0645\\u0632\\u0627\\u062f \\u0627\\u0644\\u0639\\u0644\\u0646\\u064a\",\"total_display_live_auctions\":\"6\",\"live_auctions_order_by\":\"desc\",\"product_type\":\"auction\",\"page_url\":\"https:\\/\\/www.mzadat.om\\/auction-product\",\"live_auctions_descriptions\":null}','om','2025-06-24 19:48:06','2025-06-24 19:48:06'),(2,4,1,'{\"slider\":{\"1\":{\"title\":\"منصة المزادات الأولى في عُمان\",\"sub_title\":\"مرحباً بك في مزادات\",\"button_text\":\"استكشف المزادات الحية\",\"button_url\":\"/live-auction\",\"img\":\"banner-bg11-1694236521.png\",\"description\":\"اكتشف صفقات حصرية على السيارات والإلكترونيات والتحف وأكثر. انضم إلى آلاف المزايدين في عُمان واربح منتجات مذهلة بأسعار لا تُقاوم.\"},\"2\":{\"title\":\"زايد بذكاء، اربح أكثر\",\"sub_title\":\"موثوق من الآلاف\",\"button_text\":\"ابدأ المزايدة الآن\",\"button_url\":\"/live-auction\",\"img\":\"banner-bg22-1694236546.png\",\"description\":\"استمتع بإثارة المزادات الحية. من السلع الفاخرة إلى المستلزمات اليومية، اعثر على صفقتك التالية مع نظام مزادات الآمن والشفاف.\"},\"3\":{\"title\":\"بِع منتجاتك للآلاف\",\"sub_title\":\"كن تاجراً\",\"button_text\":\"سجل كبائع\",\"button_url\":\"/merchant/register\",\"img\":\"banner-bg11-1694236521.png\",\"description\":\"وصل إلى المشترين في جميع أنحاء عُمان وطوّر عملك. اعرض منتجاتك، حدد أسعارك، ودع منصتنا تربطك بالمزايدين المتحمسين.\"}}}','om','2026-01-25 16:51:37','2026-01-25 16:51:37');
