INSERT INTO `widget_contents` (`id`, `page_id`, `widget_slug`, `ui_card_number`, `widget_content`, `position`, `status`, `created_at`, `updated_at`) VALUES (1,1,'latest-product','9311884','{\"live_auctions_title\":\"Live Auction\",\"total_display_live_auctions\":\"6\",\"live_auctions_order_by\":\"desc\",\"product_type\":\"auction\",\"page_url\":\"https:\\/\\/www.mzadat.om\\/auction-product\",\"live_auctions_descriptions\":\"\"}',4,1,'2024-01-21 19:05:00','2025-06-29 13:30:14'),(2,1,'up-coming-auctions','93d31af','{\"upcoming_auctions_main_title\":\"Up Coming\",\"upcoming_auctions_descriptions\":\"\",\"total_upcoming_auctions_display\":\"4\",\"upcoming_auctions_order_by\":\"asc\",\"product_type\":\"1\",\"page_url\":\"https:\\/\\/www.mzadat.om\\/auction-product\"}',5,0,'2024-01-21 19:05:00','2025-06-29 13:30:17'),(4,1,'sliders','c00f61b','{\"slider\":{\"1\":{\"title\":\"Oman\'s Premier Online Auction Platform\",\"sub_title\":\"Welcome to Mzadat\",\"button_text\":\"Explore Live Auctions\",\"button_url\":\"/live-auction\",\"img\":\"banner-bg11-1694236521.png\",\"description\":\"Discover exclusive deals on cars, electronics, antiques, and more. Join thousands of bidders across Oman and win amazing products at unbeatable prices.\"},\"2\":{\"title\":\"Bid Smart, Win Big\",\"sub_title\":\"Trusted by Thousands\",\"button_text\":\"Start Bidding Now\",\"button_url\":\"/live-auction\",\"img\":\"banner-bg22-1694236546.png\",\"description\":\"Experience the thrill of real-time auctions. From luxury items to everyday essentials, find your next great deal with Mzadat\'s secure and transparent bidding system.\"},\"3\":{\"title\":\"Sell Your Products to Thousands\",\"sub_title\":\"Become a Merchant\",\"button_text\":\"Register as Seller\",\"button_url\":\"/merchant/register\",\"img\":\"banner-bg11-1694236521.png\",\"description\":\"Reach buyers across Oman and grow your business. List your products, set your prices, and let our platform connect you with eager bidders.\"}}}',1,0,'2024-01-21 19:05:00','2025-05-28 12:36:40'),(5,1,'testimonial','a84322a','{\"testimonial_main_title\":\"What Client Say\",\"testimonial_main_descriptions\":\"Ive been using it to sell my items, and I couldnt be happier with the results. The platform is user-friendly, and I was able to reach a wide audience for my auctions. The seamless bidding process and secure transactions make it my go-to choice for online auctions.\",\"testimonials\":{\"1\":{\"testimonial_name\":\"Johan Martin\",\"testimonial_designations\":\"CEO\",\"img\":\"yannie_tan-1694255143.jpg\",\"testimonial_descriptions\":\"As a frequent buyer on I appreciate the diverse range of items available and the excitement of the bidding process. The websites intuitive design and transparent information about each listing make it easy to find and bid on items I love.\"},\"2\":{\"testimonial_name\":\"Jamie anderson\",\"testimonial_designations\":\"CTO\",\"img\":\"nadia_k-1694255143.jpg\",\"testimonial_descriptions\":\"Our company has been using it to liquidate excess inventory, and the results have exceeded our expectations. The platforms reach, combined with its efficient auction management tools, has streamlined our selling process and maximized returns.\"},\"3\":{\"testimonial_name\":\"Jhon Peter\",\"testimonial_designations\":\"Manager\",\"img\":\"jeremy_mcKeehen-1694257879.jpg\",\"testimonial_descriptions\":\"Being a collector, Ive explored various auction platforms, and BidOut stands out for its diverse selection and reputable sellers. The platform provides a reliable and secure environment for both buyers and sellers.\"},\"4\":{\"testimonial_name\":\"Johan Martin\",\"testimonial_designations\":\"Asst. Manager\",\"img\":\"mahesh_fonseka-1694257879.jpg\",\"testimonial_descriptions\":\"Our charity organization has successfully hosted online fundraisers using Bidout. The platforms support for charitable auctions, coupled with its user-friendly interface, has allowed us to connect with generous donors and raise funds for our cause.\"}}}',6,0,'2024-01-21 19:05:00','2025-06-29 13:30:06'),(7,1,'categories','f58932b','{\"total_display_categories\":\"20\",\"category_order_type\":\"desc\"}',3,0,'2024-01-21 19:05:00','2025-06-29 13:30:06'),(8,2,'about-content','e1e9db8','{\"about_content_title\":\"\\u0646\\u062d\\u0646 \\u0646\\u0639\\u0645\\u0644 \\u0645\\u0646 \\u0623\\u062c\\u0644 \\u0646\\u062c\\u0627\\u062d\\u0643 \\u0627\\u0644\\u0645\\u0630\\u0647\\u0644\",\"about_content_sub_title\":\"\\u0645\\u0646 \\u0646\\u062d\\u0646!\",\"img\":\"egens-PyfTqlnpLm.webp\",\"total_raised\":\"\",\"about_content_btn_text\":\"\",\"about_content_btn_url\":\"\",\"about_content_descriptions\":\"<div>\\u0646\\u062d\\u0646 \\u0634\\u0631\\u0643\\u0629 \\u0639\\u064f\\u0645\\u0627\\u0646\\u064a\\u0629 \\u0645\\u062a\\u062e\\u0635\\u0635\\u0629 \\u0641\\u064a \\u062a\\u0646\\u0638\\u064a\\u0645 \\u0648\\u0625\\u062f\\u0627\\u0631\\u0629 \\u0627\\u0644\\u0645\\u0632\\u0627\\u062f\\u0627\\u062a\\u060c \\u0646\\u0639\\u0645\\u0644 \\u0628\\u0645\\u0647\\u0646\\u064a\\u0629 \\u0639\\u0627\\u0644\\u064a\\u0629 \\u0648\\u0646\\u0644\\u062a\\u0632\\u0645 \\u0628\\u062a\\u0642\\u062f\\u064a\\u0645 \\u062a\\u062c\\u0631\\u0628\\u0629 \\u0645\\u0632\\u0627\\u064a\\u062f\\u0629 \\u0639\\u0627\\u062f\\u0644\\u0629\\u060c \\u0634\\u0641\\u0627\\u0641\\u0629\\u060c \\u0648\\u0622\\u0645\\u0646\\u0629 \\u0644\\u0643\\u0627\\u0641\\u0629 \\u0627\\u0644\\u0623\\u0637\\u0631\\u0627\\u0641.\\u00a0\\u00a0<\\/div><div><br \\/><\\/div><div>\\u0646\\u064f\\u0633\\u062e\\u0651\\u0631 \\u0623\\u062d\\u062f\\u062b \\u0627\\u0644\\u062a\\u0642\\u0646\\u064a\\u0627\\u062a \\u0648\\u0627\\u0644\\u0645\\u0646\\u0635\\u0627\\u062a \\u0627\\u0644\\u0630\\u0643\\u064a\\u0629 \\u0644\\u062a\\u0633\\u0647\\u064a\\u0644 \\u0627\\u0644\\u0648\\u0635\\u0648\\u0644 \\u0625\\u0644\\u0649 \\u0627\\u0644\\u0641\\u0631\\u0635 \\u0627\\u0644\\u0627\\u0633\\u062a\\u062b\\u0645\\u0627\\u0631\\u064a\\u0629\\u060c \\u0628\\u0645\\u0627 \\u064a\\u062a\\u0645\\u0627\\u0634\\u0649 \\u0645\\u0639 \\u062a\\u0637\\u0644\\u0639\\u0627\\u062a \\u0627\\u0644\\u0633\\u0648\\u0642 \\u0627\\u0644\\u0639\\u064f\\u0645\\u0627\\u0646\\u064a \\u0648\\u064a\\u0639\\u0632\\u0632 \\u0645\\u0646 \\u062a\\u062d\\u0642\\u064a\\u0642 \\u0623\\u0647\\u062f\\u0627\\u0641 \\u0631\\u0624\\u064a\\u0629 \\u0639\\u064f\\u0645\\u0627\\u0646 2040.\\u00a0\\u00a0<\\/div><div><br \\/><\\/div><div>\\u0646\\u0648\\u0644\\u064a \\u0623\\u0647\\u0645\\u064a\\u0629 \\u0642\\u0635\\u0648\\u0649 \\u0644\\u0636\\u0645\\u0627\\u0646 \\u0627\\u0644\\u062d\\u0645\\u0627\\u064a\\u0629 \\u0627\\u0644\\u0642\\u0627\\u0646\\u0648\\u0646\\u064a\\u0629 \\u0644\\u062d\\u0642\\u0648\\u0642 \\u0627\\u0644\\u0645\\u0634\\u0627\\u0631\\u0643\\u064a\\u0646\\u060c \\u0648\\u0646\\u0639\\u062a\\u0645\\u062f \\u0639\\u0644\\u0649 \\u0623\\u0639\\u0644\\u0649 \\u0645\\u0639\\u0627\\u064a\\u064a\\u0631 \\u0627\\u0644\\u0646\\u0632\\u0627\\u0647\\u0629 \\u0648\\u0627\\u0644\\u062d\\u0648\\u0643\\u0645\\u0629 \\u0627\\u0644\\u0631\\u0642\\u0645\\u064a\\u0629 \\u0641\\u064a \\u062c\\u0645\\u064a\\u0639 \\u0639\\u0645\\u0644\\u064a\\u0627\\u062a\\u0646\\u0627\\u060c \\u0625\\u064a\\u0645\\u0627\\u0646\\u064b\\u0627 \\u0645\\u0646\\u0627 \\u0628\\u0623\\u0647\\u0645\\u064a\\u0629 \\u0628\\u0646\\u0627\\u0621 \\u0627\\u0644\\u062b\\u0642\\u0629 \\u0648\\u062a\\u0645\\u0643\\u064a\\u0646 \\u0627\\u0644\\u0623\\u0641\\u0631\\u0627\\u062f \\u0648\\u0627\\u0644\\u0634\\u0631\\u0643\\u0627\\u062a \\u0645\\u0646 \\u0627\\u0644\\u0628\\u064a\\u0639 \\u0648\\u0627\\u0644\\u0634\\u0631\\u0627\\u0621 \\u0628\\u0643\\u0644 \\u064a\\u064f\\u0633\\u0631 \\u0648\\u0627\\u0637\\u0645\\u0626\\u0646\\u0627\\u0646.<\\/div><div><br \\/><\\/div>\"}',1,1,'2024-01-21 19:05:00','2026-01-29 18:12:16'),(9,2,'features','9b87e5e','{\"features_main_title\":\"Why Choose Us\",\"features_main_descriptions\":\"We are tirelessly scours the globe to present you with only the most exceptional pieces, ensuring each auction is a showcase of excellence.\",\"features\":{\"1\":{\"name\":\"Legal Framework\",\"img\":\"egens-H5G6n10Zg7.webp\",\"descriptions\":\"We prepare and review the auction\\u2019s terms and conditions to ensure compliance with regulations and instructions. We also ensure the auction is officially documented following the Ministry of Finance\\u2019s approved procedures. To guarantee everyone\\u2019s rights, we provide legal protection for all clients and participants in the auction.\"},\"2\":{\"name\":\"Marketing and Promotion\",\"img\":\"egens-2FfRKW5kVP.webp\",\"descriptions\":\"For every auction, we prepare a tailored digital marketing plan that ensures precise targeting of the intended audience. We use popular social media channels to increase engagement and reach, and communicate directly with qualified bidders through specialized WhatsApp groups. Additionally, we design professional ads that attract attention and highlight the value and credibility of the items in a distinctive manner.\"},\"3\":{\"name\":\"Professional Photography and Presentation\",\"img\":\"egens-xg15BeWncW.webp\",\"descriptions\":\"We emphasize presenting each product and asset in the best light through high-quality professional photography and videos that capture details accurately. We provide engaging descriptions that highlight the main features and strengths of each item. Then, we upload the materials to the auction platform with a neat and easy-to-use layout to ensure a comfortable and attractive experience for bidders.\"},\"4\":{\"name\":\"Transparency and Monitoring\",\"img\":\"egens-ikr2MbMR2g.webp\",\"descriptions\":\"Because trust is our priority, we offer a secure and transparent bidding system that allows participants to follow every step of the bidding process in real-time. We provide immediate daily reports on auction progress and complete documentation of every bid, including price, time, and username \\u2014 ensuring a fair and clear experience for all parties.\"},\"5\":{\"name\":\"Additional Services:\",\"img\":\"egens-Cb4YIOjlAb.webp\",\"descriptions\":\"To guarantee a smooth and comprehensive experience, we provide direct technical support for bidders during the auction. We handle collection management and payment follow-ups flexibly, while dedicating an auction page that professionally reflects the client\\u2019s identity. After the auction, we deliver a detailed report of results and activities, along with full supervision of loading and cleaning materials to ensure delivery in optimal condition.\"}}}',4,1,'2024-01-21 19:05:00','2025-06-15 16:03:14'),(11,2,'fun-facts','9e49609',NULL,5,0,'2024-01-21 19:05:00','2025-06-15 15:50:12'),(12,3,'procedures','8b20657','{\"procedures\":{\"1\":{\"name\":\"Register Now & Start Selleing Your Things\",\"img\":\"egens-AQ4uTeHjEa.png\",\"button_text\":\"Register Account\",\"button_url\":\"#\",\"description\":\"Users need to create an account on the auction website. This usually involves providing personal information, creating a username, and setting a password. Some auction websites may require users to verify their email address or mobile number to activate their accounts.\\r\\n\\r\\nUsers can browse through a variety of product listings on the auction website. These listings may include images, detailed descriptions, and starting bid prices.\"},\"2\":{\"name\":\"Select Your Item\",\"img\":\"egens-HF2SWEktqW.png\",\"button_text\":\"Add Your Item\",\"button_url\":\"#\",\"description\":\"Interested buyers can participate in auctions by placing bids on items they wish to purchase. Each bid increases the current bid amount, and the auction continues until a specified end time. Users can monitor the progress of auctions theyre interested in. Notifications or alerts may be provided to inform users if they are outbid.\\r\\n\\r\\nThe user with the highest bid at the end of the auction wins the item. Some auction websites may employ automatic bidding systems where users can set a maximum bid, and the system automatically places bids on their behalf until the maximum is reached.\"},\"3\":{\"name\":\"Purcahse Items\",\"img\":\"egens-dmUZhCh2mE.png\",\"button_text\":\"Purchase Item\",\"button_url\":\"#\",\"description\":\"After winning an auction, the buyer needs to proceed with payment. The auction website typically provides multiple payment options, such as credit\\/debit cards, online payment platforms, or other forms of electronic payment. Buyers are required to provide shipping details, including the shipping address. Some auction websites may offer integrated shipping services or partnerships with logistics companies.\\r\\n\\r\\nOnce payment is confirmed, the seller ships the item to the buyer. Buyers receive the purchased item and can confirm the receipt on the auction website.\"}}}',1,1,'2024-01-21 19:05:00','2024-01-21 19:05:00'),(13,3,'features','e89d8bc','{\"features_main_title\":\"Why Choose Us\",\"features_main_descriptions\":\"We are tirelessly scours the globe to present you with only the most exceptional pieces, ensuring each auction is a showcase of excellence.\",\"features\":{\"1\":{\"name\":\"High Quality Products\",\"img\":\"egens-wJUuauRLgJ.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"},\"2\":{\"name\":\"Creator\\u2019s Royalty\",\"img\":\"egens-lzoidzt6ue.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"},\"3\":{\"name\":\"Support Multiple Currency\",\"img\":\"egens-vHMq1w1xqn.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"},\"4\":{\"name\":\"Top Calss Product Price\",\"img\":\"egens-njPwoltYRx.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"},\"5\":{\"name\":\"Show All Bidders History\",\"img\":\"egens-ca84v9keKT.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"},\"6\":{\"name\":\"100% Happy Customer\",\"img\":\"egens-2kTQwCFX0I.svg\",\"descriptions\":\"Explore on the worldsbest & largest Bidding marketplace with our beautiful Bidding products. We want to be a part of your smile, success and future growth.\"}}}',2,1,'2024-01-21 19:05:00','2024-01-21 19:05:00'),(14,3,'fun-facts','4202d34','{\"fun_facts\":{\"1\":{\"title\":\"Happy Customer\",\"number_count\":\"5400\",\"img\":\"employee-1694260644.svg\"},\"2\":{\"title\":\"Good Reviews\",\"number_count\":\"1250\",\"img\":\"review-1694260644.svg\"},\"3\":{\"title\":\"Winner Customer\",\"number_count\":\"4250\",\"img\":\"smily-1694260644.svg\"},\"4\":{\"title\":\"New Comments\",\"number_count\":\"500\",\"img\":\"comment-1694260644.svg\"}}}',3,1,'2024-01-21 19:05:00','2024-01-21 19:05:00'),(16,5,'code-editor','39b6e9e','{\"content\":\"<p style=\\\"text-align:center;\\\"><b><u><span style=\\\"font-size:14pt;font-family:Tahoma;\\\">\\u0627\\u0644\\u0634\\u0631\\u0648\\u0637\\n\\u0648\\u0627\\u0644\\u0623\\u062d\\u0643\\u0627\\u0645<\\/span><\\/u><\\/b><\\/p><p style=\\\"text-align:justify;\\\"><span style=\\\"font-size:12pt;font-family:Arial, sans-serif;\\\">\\u00a0<\\/span><\\/p><p style=\\\"text-align:justify;\\\"><b><span style=\\\"font-size:12pt;\\\">1.<span style=\\\"font-weight:normal;font-size:7pt;font-family:\'Times New Roman\';\\\">\\u00a0\\u00a0\\u00a0\\u00a0\\n<\\/span><\\/span><\\/b><b><span style=\\\"font-size:12pt;font-family:Arial, sans-serif;\\\">\\u062a\\u0639\\u0631\\u064a\\u0641\\u0627\\u062a<\\/span><\\/b><b><span style=\\\"font-size:12pt;font-family:Arial, sans-serif;\\\">:<\